  "finding_id": "openscap_062",
  "safe": true,
  "verdict_reason": "The remediation correctly sets user.max_user_namespaces to 0 via a persistent sysctl drop‑in for hardened hosts and provides a safe non‑zero override for container hosts. This parameter only controls creation of unprivileged user namespaces and does not affect core system services such as sshd, firewalld, or auditd. The plan includes immediate application, persistence across reboots, and testing steps, making it unlikely to cause outages or lockouts.",
  "side_effects": [
    "Programs that rely on unprivileged user namespaces (e.g., root‑less containers, flatpak, snap, bubblewrap) will be unable to run on hosts where the value is set to 0",
    "If the override file is missing on a container host, container runtimes may fail to start"
  ],
  "services_affected": [
    "Container runtimes (Docker, Podman, CRI‑O, LXC) – only when the value is forced to 0 on hosts that need them"
  ],
  "recommendation": "Approve"
}

